@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  font-family: "Figtree", sans-serif;
  margin: 0;
  padding: 0;
}

.navbar {
  background: #05042E;
  border-radius: 10px;
  padding: 14px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.nav-left {
  display: flex;
  align-items: center;
}

.nav-logo {
  height: 36px;
  width: auto;
  display: block;
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 4px;
}

.nav-link {
  color: rgba(255, 255, 255, 0.7);
  font-size: 13px;
  font-weight: 600;
  padding: 8px 14px;
  border-radius: 6px;
  cursor: pointer;
  white-space: nowrap;
}

.nav-link:hover {
  color: #fff;
  background: rgba(255, 255, 255, 0.08);
}

.nav-link.active {
  color: #05042E;
  background: #A3E851;
}

.nav-avatar-wrap {
  position: relative;
}

.nav-avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: #469BC0;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
}

.nav-dropdown {
  display: none;
  position: absolute;
  top: 40px;
  right: 0;
  background: #fff;
  border-radius: 8px;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
  min-width: 140px;
  overflow: hidden;
  z-index: 10;
}

.nav-dropdown.open {
  display: block;
}

.nav-dropdown-item {
  padding: 10px 14px;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  cursor: pointer;
}

.nav-dropdown-item:hover {
  background: rgba(5, 4, 46, 0.05);
}

