var NAV_ITEMS = [{
  label: 'Home',
  page: 'Home'
}, {
  label: 'Customers',
  page: 'Customer_List'
}, {
  label: 'Collections',
  page: 'Upcoming Collection'
}, {
  label: 'Assets',
  page: 'Asset List'
}, {
  label: 'Pallets',
  page: 'Waste_Detail_Page'
}, {
  label: 'Sales',
  page: 'SalesRecords'
}, {
  label: 'Admin',
  page: 'Admin_Console'
}];
function escHtml(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function render(model) {
  var linksEl = document.getElementById('nav_links');
  if (!linksEl) return;
  var currentPage = model && model.currentPage || '';
  linksEl.innerHTML = NAV_ITEMS.map(function (item) {
    var isActive = item.page === currentPage;
    return '<div class="nav-link' + (isActive ? ' active' : '') + '" data-page="' + item.page + '">' + escHtml(item.label) + '</div>';
  }).join('');
  linksEl.querySelectorAll('.nav-link').forEach(function (el) {
    el.addEventListener('click', function () {
      appsmith.updateModel({
        targetPage: this.dataset.page
      });
      appsmith.triggerEvent('onNavClick');
    });
  });
  var avatar = document.getElementById('nav_avatar');
  if (avatar) {
    avatar.textContent = model && model.userInitials || '';
    avatar.addEventListener('click', function () {
      appsmith.triggerEvent('onSignOutClick');
    });
  }
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function () {
    render(appsmith.model);
  });
  appsmith.onModelChange(function (model) {
    render(model);
  });
}
initWhenReady();

